#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
struct UnicornImportCountKey {
    module: String,
    ordinal: Option<u32>,
    name: Option<String>,
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
struct UnicornImportStats {
    count: u64,
    max_a0: u32,
    max_a1: u32,
    max_a2: u32,
    max_a3: u32,
}

impl UnicornImportStats {
    fn record(&mut self, a0: u32, a1: u32, a2: u32, a3: u32) {
        self.count = self.count.saturating_add(1);
        self.max_a0 = self.max_a0.max(a0);
        self.max_a1 = self.max_a1.max(a1);
        self.max_a2 = self.max_a2.max(a2);
        self.max_a3 = self.max_a3.max(a3);
    }
}

#[cfg(feature = "unicorn")]
fn unicorn_window_snapshot(window: crate::ce::gwe::Window) -> UnicornWindowSnapshot {
    UnicornWindowSnapshot {
        hwnd: window.hwnd,
        thread_id: window.thread_id,
        process_id: window.process_id,
        class_name: window.class_name,
        title: window.title,
        visible: window.visible,
        being_destroyed: window.being_destroyed,
        destroyed: window.destroyed,
        parent: window.parent,
        owner: window.owner,
        style: window.style,
        ex_style: window.ex_style,
        update_pending: window.update_pending,
        erase_pending: window.erase_pending,
        pending_move: window.pending_move,
        pending_size: window.pending_size,
        rect: window.rect,
        client_rect: window.client_rect,
        update_rect: window.update_rects.iter().copied().reduce(crate::ce::gwe::Rect::union).unwrap_or_default(),
        wndproc: window.wndproc,
    }
}

