enum WinsockReadyKind {
    Read,
    Write,
    ReadWrite,
    Except,
}

#[cfg(feature = "unicorn")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum BlockedWaitKind {
    Kernel,
    Sleep,
    MsgWait {
        wake_mask: u32,
        input_available: bool,
    },
    SerialRead {
        handle: u32,
        buffer: u32,
        requested: u32,
        transferred_ptr: u32,
    },
    SerialCommEvent {
        handle: u32,
        event_ptr: u32,
    },
    WinsockRead {
        socket: u32,
        readiness: WinsockReadyKind,
        read_mask: u64,
        write_mask: u64,
        except_mask: u64,
        name: Option<&'static str>,
        ordinal: Option<u32>,
        args: [u32; 6],
    },
    SendMessage {
        send_id: u64,
        receiver_thread_id: u32,
        result_ptr: Option<u32>,
        previous_running_thread: Option<(u32, u32)>,
    },
}

#[cfg(feature = "unicorn")]
#[derive(Debug, Clone, PartialEq, Eq)]
struct BlockedWaitThread {
    wait_id: u64,
    thread_id: u32,
    thread_handle: u32,
    wait_handles: Vec<u32>,
    kind: BlockedWaitKind,
    wait_started_ms: u32,
    timeout_ms: u32,
    regs: MipsGuestContext,
    return_pc: u32,
}

#[cfg(feature = "unicorn")]
fn scheduler_blocked_wait_kind(
    kind: BlockedWaitKind,
) -> crate::ce::scheduler::SchedulerBlockedWaitKind {
    match kind {
        BlockedWaitKind::Kernel => crate::ce::scheduler::SchedulerBlockedWaitKind::Kernel,
        BlockedWaitKind::Sleep => crate::ce::scheduler::SchedulerBlockedWaitKind::Sleep,
        BlockedWaitKind::MsgWait {
            wake_mask,
            input_available,
        } => crate::ce::scheduler::SchedulerBlockedWaitKind::MsgWait {
            wake_mask,
            input_available,
        },
        BlockedWaitKind::SerialRead { handle, .. } => {
            crate::ce::scheduler::SchedulerBlockedWaitKind::SerialRead { handle }
        }
        BlockedWaitKind::SerialCommEvent { handle, .. } => {
            crate::ce::scheduler::SchedulerBlockedWaitKind::SerialCommEvent { handle }
        }
        BlockedWaitKind::WinsockRead {
            socket,
            readiness,
            read_mask,
            write_mask,
            except_mask,
            ..
        } => crate::ce::scheduler::SchedulerBlockedWaitKind::WinsockRead {
            socket,
            readiness: scheduler_winsock_ready_kind(readiness),
            read_mask,
            write_mask,
            except_mask,
        },
        BlockedWaitKind::SendMessage { send_id, .. } => {
            crate::ce::scheduler::SchedulerBlockedWaitKind::SendMessage { send_id }
        }
    }
}

#[cfg(feature = "unicorn")]
fn scheduler_winsock_ready_kind(
    readiness: WinsockReadyKind,
) -> crate::ce::scheduler::SchedulerWinsockReadyKind {
    match readiness {
        WinsockReadyKind::Read => crate::ce::scheduler::SchedulerWinsockReadyKind::Read,
        WinsockReadyKind::Write => crate::ce::scheduler::SchedulerWinsockReadyKind::Write,
        WinsockReadyKind::ReadWrite => crate::ce::scheduler::SchedulerWinsockReadyKind::ReadWrite,
        WinsockReadyKind::Except => crate::ce::scheduler::SchedulerWinsockReadyKind::Except,
    }
}

