        let pending_returns = std::rc::Rc::new(std::cell::RefCell::new(Vec::new()));
        let current_thread_id = std::rc::Rc::new(std::cell::RefCell::new(thread_id));
        let suspended_thread = std::rc::Rc::new(std::cell::RefCell::new(None));
