    #[test]
    fn timeslice_preempts_active_thread_to_ready_blocked_waiter() {
        let config = RuntimeConfig::load("regs.json", "serial_devices.json").unwrap();
        let mut kernel = crate::ce::kernel::CeKernel::boot(config);
        let mut uc = unicorn_engine::Unicorn::new(
            unicorn_engine::Arch::MIPS,
            unicorn_engine::Mode::MIPS32 | unicorn_engine::Mode::LITTLE_ENDIAN,
        )
        .unwrap();
        let active_thread_id = super::MAIN_GUEST_THREAD_ID;
        let active_thread_handle = 0x101;
        let ready_thread_id = 6;
        let ready_thread_handle = 0x106;
        let ready_event = kernel.create_event_w(None, true, true);
        let active_pc = 0x3333_0000_u32;
        let active_ra = 0x4444_0000_u32;
        let ready_return_pc = 0x5555_0000_u32;
        let wait_id = kernel.register_blocked_waiter(
            ready_thread_id,
            ready_thread_handle,
            vec![ready_event],
            crate::ce::scheduler::SchedulerBlockedWaitKind::Kernel,
            kernel.timers.tick_count(),
            crate::ce::timer::INFINITE,
        );
        let blocked_waits = std::rc::Rc::new(std::cell::RefCell::new(vec![BlockedWaitThread {
            wait_id,
            thread_id: ready_thread_id,
            thread_handle: ready_thread_handle,
            wait_handles: vec![ready_event],
            kind: BlockedWaitKind::Kernel,
            wait_started_ms: kernel.timers.tick_count(),
            timeout_ms: crate::ce::timer::INFINITE,
            regs: super::MipsGuestContext::zero(),
            return_pc: ready_return_pc,
        }]));
        let current_thread_id = std::rc::Rc::new(std::cell::RefCell::new(active_thread_id));
        let suspended_thread = std::rc::Rc::new(std::cell::RefCell::new(None));
        let running_thread = std::rc::Rc::new(std::cell::RefCell::new(Some((
            active_thread_id,
            active_thread_handle,
        ))));
        uc.reg_write(unicorn_engine::RegisterMIPS::RA, u64::from(active_ra))
            .unwrap();

        assert!(super::try_resume_blocked_wait_with_active_pc(
            &mut kernel,
            &mut uc,
            active_thread_id,
            &current_thread_id,
            &blocked_waits,
            &suspended_thread,
            None,
            &running_thread,
            Some(active_pc),
            true,
        ));

        assert_eq!(*current_thread_id.borrow(), ready_thread_id);
        assert_eq!(
            *running_thread.borrow(),
            Some((ready_thread_id, ready_thread_handle))
        );
        let suspended = suspended_thread.borrow();
        let suspended = suspended.as_ref().unwrap();
        assert_eq!(suspended.thread_id, active_thread_id);
        assert_eq!(suspended.thread_handle, Some(active_thread_handle));
        assert_eq!(suspended.pc, active_pc);
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::V0).unwrap() as u32,
            WAIT_OBJECT_0
        );
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::PC).unwrap() as u32,
            ready_return_pc
        );
        assert!(blocked_waits.borrow().is_empty());
        assert!(kernel.blocked_waiter(wait_id).is_none());
    }

    #[test]
    fn timeslice_ready_waiter_queues_active_when_suspended_slot_is_occupied() {
        let config = RuntimeConfig::load("regs.json", "serial_devices.json").unwrap();
        let mut kernel = crate::ce::kernel::CeKernel::boot(config);
        let mut uc = unicorn_engine::Unicorn::new(
            unicorn_engine::Arch::MIPS,
            unicorn_engine::Mode::MIPS32 | unicorn_engine::Mode::LITTLE_ENDIAN,
        )
        .unwrap();
        let active_thread_id = super::MAIN_GUEST_THREAD_ID;
        let active_thread_handle = 0x101;
        let old_suspended_thread_id = 4;
        let ready_thread_id = 6;
        let ready_thread_handle = 0x106;
        let ready_event = kernel.create_event_w(None, true, true);
        let active_pc = 0x3333_0000_u32;
        let ready_return_pc = 0x5555_0000_u32;
        let active_hi = 0x1111_2222_u32;
        let active_lo = 0x3333_4444_u32;
        let ready_hi = 0xaaaa_5555_u32;
        let ready_lo = 0xbbbb_6666_u32;
        let wait_id = kernel.register_blocked_waiter(
            ready_thread_id,
            ready_thread_handle,
            vec![ready_event],
            crate::ce::scheduler::SchedulerBlockedWaitKind::Kernel,
            kernel.timers.tick_count(),
            crate::ce::timer::INFINITE,
        );
        let mut ready_regs = super::MipsGuestContext::zero();
        ready_regs.hi = ready_hi;
        ready_regs.lo = ready_lo;
        let blocked_waits = std::rc::Rc::new(std::cell::RefCell::new(vec![BlockedWaitThread {
            wait_id,
            thread_id: ready_thread_id,
            thread_handle: ready_thread_handle,
            wait_handles: vec![ready_event],
            kind: BlockedWaitKind::Kernel,
            wait_started_ms: kernel.timers.tick_count(),
            timeout_ms: crate::ce::timer::INFINITE,
            regs: ready_regs,
            return_pc: ready_return_pc,
        }]));
        let current_thread_id = std::rc::Rc::new(std::cell::RefCell::new(active_thread_id));
        let suspended_thread =
            std::rc::Rc::new(std::cell::RefCell::new(Some(super::SuspendedGuestThread {
                thread_id: old_suspended_thread_id,
                thread_handle: Some(0x104),
                regs: super::MipsGuestContext::zero(),
                pc: 0x4444_0000,
            })));
        let suspended_queue =
            std::rc::Rc::new(std::cell::RefCell::new(std::collections::VecDeque::new()));
        suspended_queue
            .borrow_mut()
            .push_back(super::SuspendedGuestThread {
                thread_id: ready_thread_id,
                thread_handle: Some(ready_thread_handle),
                regs: super::MipsGuestContext::zero(),
                pc: 0x6666_0000,
            });
        let running_thread = std::rc::Rc::new(std::cell::RefCell::new(Some((
            active_thread_id,
            active_thread_handle,
        ))));
        uc.reg_write(unicorn_engine::RegisterMIPS::HI, u64::from(active_hi))
            .unwrap();
        uc.reg_write(unicorn_engine::RegisterMIPS::LO, u64::from(active_lo))
            .unwrap();

        assert!(super::try_resume_blocked_wait_with_active_pc(
            &mut kernel,
            &mut uc,
            active_thread_id,
            &current_thread_id,
            &blocked_waits,
            &suspended_thread,
            Some(&suspended_queue),
            &running_thread,
            Some(active_pc),
            true,
        ));

        assert_eq!(*current_thread_id.borrow(), ready_thread_id);
        assert_eq!(
            *running_thread.borrow(),
            Some((ready_thread_id, ready_thread_handle))
        );
        assert_eq!(
            suspended_thread.borrow().as_ref().unwrap().thread_id,
            old_suspended_thread_id
        );
        let queue = suspended_queue.borrow();
        assert_eq!(queue.len(), 1);
        assert_eq!(queue[0].thread_id, active_thread_id);
        assert_eq!(queue[0].thread_handle, Some(active_thread_handle));
        assert_eq!(queue[0].pc, active_pc);
        assert_eq!(queue[0].regs.hi, active_hi);
        assert_eq!(queue[0].regs.lo, active_lo);
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::HI).unwrap() as u32,
            ready_hi
        );
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::LO).unwrap() as u32,
            ready_lo
        );
        assert!(blocked_waits.borrow().is_empty());
        assert!(kernel.blocked_waiter(wait_id).is_none());
    }

    #[test]
    fn timeslice_can_switch_from_main_thread_without_running_handle() {
        let config = RuntimeConfig::load("regs.json", "serial_devices.json").unwrap();
        let kernel = crate::ce::kernel::CeKernel::boot(config);
        let mut uc = unicorn_engine::Unicorn::new(
            unicorn_engine::Arch::MIPS,
            unicorn_engine::Mode::MIPS32 | unicorn_engine::Mode::LITTLE_ENDIAN,
        )
        .unwrap();
        let main_thread_id = super::MAIN_GUEST_THREAD_ID;
        let worker_thread_id = 6;
        let worker_thread_handle = 0x106;
        let main_pc = 0x3333_0000_u32;
        let worker_pc = 0x5555_0000_u32;
        let current_thread_id = std::rc::Rc::new(std::cell::RefCell::new(main_thread_id));
        let suspended_thread =
            std::rc::Rc::new(std::cell::RefCell::new(Some(super::SuspendedGuestThread {
                thread_id: worker_thread_id,
                thread_handle: Some(worker_thread_handle),
                regs: super::MipsGuestContext::zero(),
                pc: worker_pc,
            })));
        let suspended_queue =
            std::rc::Rc::new(std::cell::RefCell::new(std::collections::VecDeque::new()));
        let running_thread = std::rc::Rc::new(std::cell::RefCell::new(None));
        uc.reg_write(unicorn_engine::RegisterMIPS::V0, 0xaaaa_0001)
            .unwrap();

        assert!(super::try_timeslice_to_suspended_thread(
            &kernel,
            &mut uc,
            main_thread_id,
            main_pc,
            &current_thread_id,
            &suspended_thread,
            &suspended_queue,
            &running_thread,
        ));

        assert_eq!(*current_thread_id.borrow(), worker_thread_id);
        assert_eq!(
            *running_thread.borrow(),
            Some((worker_thread_id, worker_thread_handle))
        );
        assert_eq!(
            uc.reg_read(unicorn_engine::RegisterMIPS::PC).unwrap() as u32,
            worker_pc
        );
        let suspended = suspended_thread.borrow();
        let suspended = suspended.as_ref().unwrap();
        assert_eq!(suspended.thread_id, main_thread_id);
        assert_eq!(suspended.thread_handle, None);
        assert_eq!(suspended.pc, main_pc);
        assert!(suspended_queue.borrow().is_empty());
    }

    #[test]
    fn timeslice_skips_control_transfer_targets() {
        assert!(!super::is_control_transfer_target(None, 0x1000));
        assert!(!super::is_control_transfer_target(Some(0x1000), 0x1004));
        assert!(super::is_control_transfer_target(Some(0x1004), 0x2000));
        assert!(super::is_control_transfer_target(Some(0x2000), 0x1008));
    }

    #[test]
    fn timeslice_pending_survives_unsafe_sample_until_safe_pc() {
        let pending = std::cell::Cell::new(true);
        assert!(!super::scheduler_timeslice_consume_if_safe(&pending, false));
        assert!(pending.get());
        assert!(super::scheduler_timeslice_consume_if_safe(&pending, true));
        assert!(!pending.get());
        assert!(!super::scheduler_timeslice_consume_if_safe(&pending, true));
    }

    #[test]
    fn timeslice_identifies_mips_delay_slot_instructions() {
        assert!(super::is_mips_control_transfer_instruction(0x0800_1000)); // j
        assert!(super::is_mips_control_transfer_instruction(0x0c00_1000)); // jal
        assert!(super::is_mips_control_transfer_instruction(0x03e0_0008)); // jr ra
        assert!(super::is_mips_control_transfer_instruction(0x00e0_f809)); // jalr ra,a3
        assert!(super::is_mips_control_transfer_instruction(0x04c0_004c)); // bltz a2
        assert!(super::is_mips_control_transfer_instruction(0x50a0_0003)); // beql a1,zero
        assert!(super::is_mips_control_transfer_instruction(0x4501_0002)); // bc1t
        assert!(!super::is_mips_control_transfer_instruction(0x8ca5_0008)); // lw a1,8(a1)
        assert!(!super::is_mips_control_transfer_instruction(0x0000_0000)); // nop
    }

    #[test]
    fn pending_guest_thread_return_is_owned_by_worker_thread() {
        let pending_returns = std::rc::Rc::new(std::cell::RefCell::new(vec![
            super::PendingGuestThreadReturn {
                creator_thread_id: 1,
                worker_thread_id: 6,
                thread_handle: 0x106,
                return_pc: 0x1111_0000,
                creator_regs: super::MipsGuestContext::zero(),
            },
        ]));

        assert!(super::pop_pending_guest_thread_return_for_thread(&pending_returns, 7).is_none());
        assert_eq!(pending_returns.borrow().len(), 1);

        let callout =
            super::pop_pending_guest_thread_return_for_thread(&pending_returns, 6).unwrap();
        assert_eq!(callout.worker_thread_id, 6);
        assert!(pending_returns.borrow().is_empty());
    }

    #[test]
    fn stale_blocked_wait_cleanup_removes_prior_context_for_thread() {
        let config = RuntimeConfig::load("regs.json", "serial_devices.json").unwrap();
        let mut kernel = crate::ce::kernel::CeKernel::boot(config);
        let event_a = kernel.create_event_w(None, true, false);
        let event_b = kernel.create_event_w(None, true, true);
        let thread_id = 7;
        let wait_a = kernel.register_blocked_waiter(
            thread_id,
            0x107,
            vec![event_a],
            crate::ce::scheduler::SchedulerBlockedWaitKind::Kernel,
            kernel.timers.tick_count(),
            crate::ce::timer::INFINITE,
        );
        let wait_b = kernel.register_blocked_waiter(
            8,
            0x108,
            vec![event_b],
            crate::ce::scheduler::SchedulerBlockedWaitKind::Kernel,
            kernel.timers.tick_count(),
            crate::ce::timer::INFINITE,
        );
        let blocked_waits = std::rc::Rc::new(std::cell::RefCell::new(vec![
            BlockedWaitThread {
                wait_id: wait_a,
                thread_id,
                thread_handle: 0x107,
                wait_handles: vec![event_a],
                kind: BlockedWaitKind::Kernel,
                wait_started_ms: 0,
                timeout_ms: crate::ce::timer::INFINITE,
                regs: super::MipsGuestContext::zero(),
                return_pc: 0,
            },
            BlockedWaitThread {
                wait_id: wait_b,
                thread_id: 8,
                thread_handle: 0x108,
                wait_handles: vec![event_b],
                kind: BlockedWaitKind::Kernel,
                wait_started_ms: 0,
                timeout_ms: crate::ce::timer::INFINITE,
                regs: super::MipsGuestContext::zero(),
                return_pc: 0,
            },
        ]));

        super::remove_stale_blocked_waits_for_thread(&mut kernel, &blocked_waits, thread_id);

        assert_eq!(blocked_waits.borrow().len(), 1);
        assert_eq!(blocked_waits.borrow()[0].wait_id, wait_b);
        let now = kernel.timers.tick_count();
        assert_eq!(
            kernel.select_ready_blocked_waiter(0, now, |blocked, _| blocked.id == wait_a),
            None
        );
        assert_eq!(
            kernel.select_ready_blocked_waiter(0, now, |blocked, _| blocked.id == wait_b),
            Some(wait_b)
        );
    }

